On a related note, at some point I wrote [some code](https://github.com/reunanen/dlib/commit/203c1fb01e59494f39291d02ebd31d2da2a81d70) to find a suitable threshold automatically. It may turn out to be helpful sometimes – especially in cases like this one, where you don't get anything (or you get lots) and you don't really know what to do.

@davisking , I would be happy to make a PR if you wanted to have that thing be part of dlib. (I even added some [tests](https://github.com/reunanen/dlib/commit/b7753cd3f736d9d45edf7bee87ec53b91f5b2e40) and [fixes](https://github.com/reunanen/dlib/commit/2fe6e7301e3cb2a4d7ceebd85c60ab472f00ff6a) after the initial commit.)
Or maybe there's already something similar in the library?

Quick update on this. I followed your suggestion regarding JSON (thanks a lot for the insight). The JSON pasted above is the intermediate format understood by the C implementation. It would be very hard to maintain hundreds of rules in such format. I implemented a hybrid: Rulesets, Statecharts and Flowcharts are framed using JSON and expression are written using a cascading API. I have written (and published to npm) the TypeScript wrapper. 

**Ruleset**  

```typescript
import * as d from 'durable';
let m = d.m, s = d.s, c = d.c;

d.ruleset('a1_1', {
    whenAll: [c['first'] = m['amount'].gt(100),
              c['second'] = m['location'].neq(c['first']['location'])],
    run: (c) => {
        console.log('fraud1 detected ' + c['first']['location'] + ' ' + c['second']['location']);
    }
});
```

**Statechart**    

```typescript
import * as d from 'durable';
let m = d.m, s = d.s, c = d.c;

d.statechart('a2_2', {
    input: [{
        to: 'denied',
        whenAll: m['subject'].eq('approve').and(m['amount'].gt(1000)),
        run: (c) => {
            console.log('a2_2 denied from: ' + c.s['sid']);
        }
    }, {
        to: 'pending', 
        whenAll: m['subject'].eq('approve').and(m['amount'].lte(1000)),
        run: (c) => {
            console.log('a2_2 request approval from: ' + c.s['sid']);
        }
    }],
    pending: [{
        to: 'pending',
        whenAll: m['subject'].eq('approved'),
        run: (c) => {
            console.log('a2_2 second request approval from: ' + c.s['sid']);
            c.s['status'] = 'approved';
        }
    }, {
        to: 'approved',
        whenAll: s['status'].eq('approved'),
        run: (c) => {
            console.log('a2_2 approved from: ' + c.s['sid']);
        }
    }, {
        to: 'denied',
        whenAll: m['subject'].eq('denied'),
        run: (c) => {
            console.log('a2_2 denied from: ' + c.s['sid']);
        }
    }],
    denied: {},
    approved: {},
});
```
**Flowchart**
```typescript
import * as d from 'durable';
let m = d.m, s = d.s, c = d.c;

d.flowchart('a3_1', {
    input: {
        request: { whenAll: m['subject'].eq('approve').and(m['amount'].lte(1000)) },
        deny: { whenAll: m['subject'].eq('approve').and(m['amount'].gt(1000)) }
    }, 
    request: {
        run: (c) => {
            console.log('a3_1 request approval from: ' + c.s['sid']);
            if (c.s['status'])
                c.s['status'] = 'approved';
            else
                c.s['status'] = 'pending';
        },
        approve: { whenAll: s['status'].eq('approved') },
        deny: { whenAll: m['subject'].eq('denied') },
        request: { whenAll: m['subject'].eq('approved') }
    },
    approve: {
        run: (c) => {
            console.log('a3_1 approved from: ' + c.s['sid']);
        }
    },
    deny: {
        run: (c) => {
            console.log('a3_1 denied from: ' + c.s['sid']);
        }
    }
});
```

